/**
 * La Fournée — Cloudflare Worker
 * KV binding: LAFOURNEE_KV
 *
 * Routes:
 *   GET  /          — serve the game HTML
 *   POST /api/save  — save game state to KV (keyed by CF-Connecting-IP)
 *   GET  /api/load  — load game state from KV
 */

const CORS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type',
};

const MAX_PAYLOAD = 64 * 1024; // 64 KB

// Embedded game HTML (generated by build.js — do not edit manually)
const GAME_HTML = "<!DOCTYPE html>\n<html lang=\"ru\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>La Fournée — Пекарня-кофейня</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=Nunito:wght@400;500;600;700&display=swap\" rel=\"stylesheet\">\n<style>\n:root{\n  --espresso:#1C0A00;--cream:#F5E6C8;--caramel:#C8873A;--sage:#4A7C59;--latte:#E8C4A0;\n  --latte2:#d4a87a;--shadow:rgba(28,10,0,.15);--red:#c0392b;\n}\n*{box-sizing:border-box;margin:0;padding:0}\nbody{font-family:'Nunito',sans-serif;background:var(--cream);color:var(--espresso);min-width:1024px;overflow-x:hidden}\n.serif{font-family:'Playfair Display',serif}\n\n/* HEADER */\n#hdr{background:var(--espresso);color:var(--cream);padding:10px 24px;display:flex;align-items:center;justify-content:space-between;box-shadow:0 2px 8px rgba(0,0,0,.35)}\n.brand{font-family:'Playfair Display',serif;font-size:22px;font-weight:700;letter-spacing:1px}\n.brand em{color:var(--caramel);font-style:normal}\n#hdr-mid{display:flex;flex-direction:column;align-items:center;gap:1px}\n#hdr-day{font-size:13px;opacity:.75;font-weight:600}\n#hdr-wx{font-size:13px;color:var(--caramel);font-weight:600}\n#hdr-r{display:flex;flex-direction:column;align-items:flex-end;gap:3px}\n#hdr-money{font-size:20px;font-weight:700;color:var(--caramel)}\n.rep-row{display:flex;align-items:center;gap:6px;font-size:12px;opacity:.8}\n#rep-bar{width:90px;height:6px;background:rgba(255,255,255,.18);border-radius:3px}\n#rep-fill{height:100%;background:var(--sage);border-radius:3px;transition:width .5s}\n\n/* NAV */\n#nav{background:var(--latte);border-bottom:2px solid var(--caramel);display:flex}\n.nb{flex:1;padding:9px 6px;border:none;background:none;cursor:pointer;font-family:'Nunito',sans-serif;font-size:13px;font-weight:600;color:var(--espresso);transition:background .18s,color .18s;border-right:1px solid var(--latte2)}\n.nb:last-child{border-right:none}\n.nb:hover{background:rgba(200,135,58,.18)}\n.nb.active{background:var(--caramel);color:#fff}\n\n/* PANELS */\n.panel{background:var(--latte);border-radius:14px;padding:16px;box-shadow:0 2px 10px var(--shadow)}\n.panel h3{font-family:'Playfair Display',serif;font-size:15px;margin-bottom:12px;border-bottom:2px solid var(--caramel);padding-bottom:6px}\n.btn{padding:9px 16px;border:none;border-radius:8px;cursor:pointer;font-family:'Nunito',sans-serif;font-weight:700;font-size:13px;transition:all .18s}\n.btn-p{background:var(--caramel);color:#fff}\n.btn-p:hover{background:#a66d28;transform:translateY(-1px);box-shadow:0 3px 8px var(--shadow)}\n.btn-s{background:var(--sage);color:#fff}\n.btn-s:hover{background:#3a6447;transform:translateY(-1px)}\n.btn-o{background:transparent;color:var(--caramel);border:2px solid var(--caramel)}\n.btn-o:hover{background:var(--caramel);color:#fff}\n.btn:active{transform:translateY(0)!important}\n\n/* ===== MORNING ===== */\n#phase-morning{display:none;padding:16px 20px;gap:16px;grid-template-columns:200px 1fr 260px}\n#phase-morning.active{display:grid}\n\n/* Ingredients */\n.ing-item{display:flex;align-items:center;gap:8px;padding:7px 10px;margin-bottom:5px;background:var(--cream);border-radius:10px;cursor:grab;border:2px solid transparent;transition:all .18s;user-select:none}\n.ing-item:hover{border-color:var(--caramel);transform:translateX(3px)}\n.ing-item:active{cursor:grabbing;opacity:.6}\n.ing-item span{font-size:12px;font-weight:600}\n\n/* Table / Drop zone */\n#drop-zone{min-height:160px;border:2.5px dashed var(--caramel);border-radius:12px;padding:10px;margin-bottom:10px;display:flex;flex-wrap:wrap;gap:8px;align-content:flex-start;transition:background .18s;position:relative}\n#drop-zone.over{background:rgba(200,135,58,.1)}\n.di{display:flex;flex-direction:column;align-items:center;gap:3px;padding:8px 10px;background:var(--cream);border-radius:10px;border:2px solid var(--caramel);cursor:pointer;transition:all .18s;min-width:64px}\n.di:hover{background:var(--caramel);color:#fff}\n.di span{font-size:10px;font-weight:600}\n#drop-hint{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;color:rgba(28,10,0,.3);font-size:13px;pointer-events:none}\n\n/* Recipe match box */\n#rec-match{padding:10px;background:rgba(74,124,89,.1);border-radius:10px;margin-bottom:10px;min-height:54px}\n.rm-label{font-size:10px;font-weight:700;color:var(--sage);text-transform:uppercase;letter-spacing:.5px;margin-bottom:5px}\n.rm-card{display:flex;align-items:center;gap:8px;padding:7px 10px;background:var(--sage);color:#fff;border-radius:8px;font-size:13px;font-weight:600}\n#exp-hint{font-size:11px;color:var(--sage);background:rgba(74,124,89,.1);border-radius:8px;padding:6px 10px;margin-bottom:8px;display:none}\n\n/* Showcase sidebar (morning) */\n.sc-item{display:flex;align-items:center;gap:7px;padding:7px 9px;background:var(--cream);border-radius:9px;margin-bottom:5px}\n.sc-item .iname{flex:1;font-size:12px;font-weight:600}\n.sc-item .iprice{font-size:11px;color:var(--caramel);font-weight:700}\n.qty{display:flex;align-items:center;gap:3px}\n.qb{width:20px;height:20px;border:1.5px solid var(--caramel);background:none;border-radius:4px;cursor:pointer;font-size:13px;color:var(--caramel);transition:all .15s;line-height:1}\n.qb:hover{background:var(--caramel);color:#fff}\n.qv{font-size:12px;font-weight:700;min-width:18px;text-align:center}\n#budget-bar{background:var(--cream);border-radius:8px;padding:9px;margin-bottom:10px;font-size:12px}\n#bprog{height:7px;background:rgba(28,10,0,.1);border-radius:4px;margin-top:4px;overflow:hidden}\n#bfill{height:100%;background:var(--caramel);border-radius:4px;transition:width .3s}\n\n/* Recipe book btn */\n#rec-book-btn{width:100%;margin-bottom:8px}\n\n/* ===== RECIPE BOOK MODAL ===== */\n#rb-overlay{display:none;position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:600;align-items:center;justify-content:center}\n#rb-overlay.active{display:flex}\n#rb-modal{background:var(--cream);border-radius:18px;padding:24px;width:680px;max-height:80vh;overflow-y:auto;box-shadow:0 8px 40px rgba(0,0,0,.35)}\n#rb-modal h2{font-family:'Playfair Display',serif;font-size:24px;margin-bottom:4px}\n#rb-modal .sub{font-size:13px;color:rgba(28,10,0,.5);margin-bottom:16px}\n.rb-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}\n.rb-card{background:var(--latte);border-radius:12px;padding:12px;display:flex;flex-direction:column;align-items:center;gap:6px;border:2px solid transparent;transition:all .18s}\n.rb-card.unlocked{border-color:rgba(200,135,58,.4)}\n.rb-card.locked{opacity:.45;filter:grayscale(.6)}\n.rb-card .rc-name{font-size:12px;font-weight:700;text-align:center}\n.rb-card .rc-price{font-size:13px;color:var(--caramel);font-weight:700}\n.rb-card .rc-ings{font-size:10px;color:rgba(28,10,0,.5);text-align:center}\n.rb-section{font-family:'Playfair Display',serif;font-size:14px;margin:12px 0 6px;color:var(--caramel)}\n\n/* ===== DAY ===== */\n#phase-day{display:none;padding:16px 20px;gap:14px;grid-template-columns:200px 1fr}\n#phase-day.active{display:grid}\n\n.sd-item{display:flex;align-items:center;gap:7px;padding:7px 8px;background:var(--cream);border-radius:9px;margin-bottom:5px;transition:all .2s}\n.sd-item.out{opacity:.35}\n.sd-item .dn{flex:1;font-size:12px;font-weight:600}\n.sd-item .dq{font-size:11px;color:var(--caramel);font-weight:700}\n\n#canvas-wrap{position:relative}\n#gc{display:block;width:100%;border-radius:14px;background:#e8d8b8}\n#day-timer{position:absolute;top:10px;right:14px;background:rgba(28,10,0,.65);color:var(--cream);padding:3px 10px;border-radius:14px;font-size:12px;font-weight:700}\n\n#sell-area{display:flex;gap:10px;justify-content:center;margin-top:10px;align-items:center}\n#cust-info{text-align:center;font-size:14px;font-weight:600;min-height:24px;margin-top:6px}\n#btn-sell{background:var(--sage);color:#fff;font-size:15px;padding:11px 30px}\n#btn-no{background:var(--espresso);color:var(--cream);font-size:15px;padding:11px 30px}\n#btn-auto{font-size:12px;padding:8px 14px}\n\n#queue-row{display:flex;gap:5px;align-items:center;justify-content:center;margin-top:8px}\n.qd{width:10px;height:10px;border-radius:50%;background:rgba(28,10,0,.12);transition:all .3s}\n.qd.on{background:var(--caramel)}\n.qd.angry{background:var(--red)}\n\n#day-log{margin-top:8px;max-height:90px;overflow-y:auto;padding:7px 9px;background:var(--latte);border-radius:9px}\n.le{font-size:11px;padding:2px 0;border-bottom:1px solid rgba(28,10,0,.05);font-weight:500}\n.le.g{color:var(--sage)}.le.b{color:var(--red)}.le.n{color:rgba(28,10,0,.55)}\n\n/* ===== EVENING ===== */\n#phase-evening{display:none;padding:24px;max-width:860px;margin:0 auto}\n#phase-evening.active{display:block}\n#ev-title{font-family:'Playfair Display',serif;font-size:30px;text-align:center;margin-bottom:4px}\n#ev-sub{text-align:center;color:rgba(28,10,0,.45);margin-bottom:22px;font-size:14px}\n.sg{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-bottom:20px}\n.sc{background:var(--latte);border-radius:12px;padding:18px;text-align:center;box-shadow:0 2px 8px var(--shadow)}\n.sc .v{font-family:'Playfair Display',serif;font-size:34px;color:var(--caramel);font-weight:700}\n.sc .l{font-size:11px;color:rgba(28,10,0,.5);margin-top:3px;text-transform:uppercase;letter-spacing:.5px}\n#ts h3,.lft-sec h3{font-family:'Playfair Display',serif;margin-bottom:12px}\n.sbr{display:flex;align-items:center;gap:9px;margin-bottom:7px}\n.sbr .nm{font-size:13px;width:140px;flex-shrink:0;font-weight:600}\n.bar-bg{flex:1;height:16px;background:rgba(28,10,0,.07);border-radius:8px;overflow:hidden}\n.bar-f{height:100%;background:var(--caramel);border-radius:8px;transition:width 1s ease}\n.sbr .cnt{font-size:12px;color:var(--caramel);font-weight:700;width:28px;text-align:right}\n.lft-item{display:flex;align-items:center;gap:9px;padding:7px;background:var(--cream);border-radius:8px;margin-bottom:5px}\n.lft-item .ln{flex:1;font-size:13px;font-weight:600}\n.lft-item .lq{font-size:11px;color:rgba(28,10,0,.5)}\n#unlock-sec{display:none;background:linear-gradient(135deg,var(--sage),#2d5c3f);border-radius:16px;padding:22px;margin-bottom:14px;color:#fff;text-align:center;animation:upop .6s ease}\n@keyframes upop{from{transform:scale(.8);opacity:0}to{transform:scale(1);opacity:1}}\n#unlock-sec h3{font-family:'Playfair Display',serif;font-size:20px}\n#unlock-name{font-size:26px;font-weight:700;color:#ffeb99;margin:6px 0}\n\n/* ===== DECOR ===== */\n#phase-decor{display:none;padding:16px 20px;gap:16px;grid-template-columns:1fr 300px}\n#phase-decor.active{display:grid}\n#dc{display:block;width:100%;border-radius:12px}\n.di-item{background:var(--cream);border-radius:10px;padding:11px;margin-bottom:9px;display:flex;align-items:center;gap:9px}\n.di-item .dico{font-size:22px;flex-shrink:0}\n.di-item .dinfo{flex:1}\n.di-item .dtitle{font-size:13px;font-weight:700}\n.di-item .ddesc{font-size:10px;color:rgba(28,10,0,.5)}\n.di-item .dprice{color:var(--caramel);font-weight:700;font-size:13px}\n.owned-badge{display:inline-block;padding:2px 8px;background:var(--sage);color:#fff;border-radius:8px;font-size:10px;font-weight:700}\n\n/* NOTIFS */\n#nw{position:fixed;top:76px;right:18px;z-index:900;display:flex;flex-direction:column;gap:7px;pointer-events:none}\n.notif{padding:9px 15px;border-radius:10px;font-size:13px;font-weight:600;animation:nin .3s ease;box-shadow:0 4px 14px rgba(0,0,0,.2)}\n@keyframes nin{from{transform:translateX(80px);opacity:0}to{transform:translateX(0);opacity:1}}\n.notif.g{background:var(--sage);color:#fff}\n.notif.b{background:var(--red);color:#fff}\n.notif.i{background:var(--espresso);color:var(--cream)}\n.notif.out{animation:nout .3s ease forwards}\n@keyframes nout{to{transform:translateX(80px);opacity:0}}\n\n/* Steam */\n@keyframes steam{0%,100%{opacity:0;transform:translateY(0) scaleX(1)}50%{opacity:.55;transform:translateY(-10px) scaleX(1.3)}}\n.sp{animation:steam 2s ease-in-out infinite}\n.sp:nth-child(2){animation-delay:.35s}\n.sp:nth-child(3){animation-delay:.7s}\n\n::-webkit-scrollbar{width:5px}\n::-webkit-scrollbar-thumb{background:var(--latte2);border-radius:3px}\n</style>\n</head>\n<body>\n\n<div id=\"hdr\">\n  <div class=\"brand\">☕ La <em>Fournée</em></div>\n  <div id=\"hdr-mid\">\n    <div id=\"hdr-day\">День 1 · Понедельник</div>\n    <div id=\"hdr-wx\">🌤 Солнечно</div>\n  </div>\n  <div id=\"hdr-r\">\n    <div id=\"hdr-money\">500 ₽</div>\n    <div class=\"rep-row\">Репутация: <span id=\"rep-pct\">50%</span><div id=\"rep-bar\"><div id=\"rep-fill\" style=\"width:50%\"></div></div></div>\n  </div>\n</div>\n\n<div id=\"nav\">\n  <button class=\"nb active\" id=\"nav-morning\" onclick=\"switchPhase('morning')\">🌅 Утро</button>\n  <button class=\"nb\" id=\"nav-day\" onclick=\"switchPhase('day')\">☀️ День</button>\n  <button class=\"nb\" id=\"nav-evening\" onclick=\"switchPhase('evening')\">🌙 Вечер</button>\n  <button class=\"nb\" id=\"nav-decor\" onclick=\"switchPhase('decor')\">🏠 Интерьер</button>\n</div>\n\n<div id=\"nw\"></div>\n\n<!-- RECIPE BOOK MODAL -->\n<div id=\"rb-overlay\">\n  <div id=\"rb-modal\">\n    <h2>📖 Книга рецептов</h2>\n    <div class=\"sub\">Перетащите ингредиенты на стол, чтобы создать блюдо</div>\n    <div class=\"rb-section\">Выпечка</div>\n    <div class=\"rb-grid\" id=\"rb-bakery\"></div>\n    <div class=\"rb-section\">Напитки</div>\n    <div class=\"rb-grid\" id=\"rb-drinks\"></div>\n    <div class=\"rb-section\" id=\"rb-special-hdr\" style=\"display:none\">Особые</div>\n    <div class=\"rb-grid\" id=\"rb-special\"></div>\n    <div style=\"margin-top:18px;text-align:right\">\n      <button class=\"btn btn-o\" onclick=\"closeRB()\">Закрыть</button>\n    </div>\n  </div>\n</div>\n\n<!-- MORNING -->\n<div id=\"phase-morning\" class=\"active\">\n  <div class=\"panel\">\n    <h3>Ингредиенты</h3>\n    <div id=\"ing-list\"></div>\n  </div>\n  <div class=\"panel\">\n    <h3>Рабочий стол</h3>\n    <div id=\"drop-zone\"><div id=\"drop-hint\">Перетащите ингредиенты сюда</div></div>\n    <div id=\"exp-hint\">✨ Неизвестная комбинация — попробуйте эксперимент!</div>\n    <div id=\"rec-match\"><div class=\"rm-label\">Распознан рецепт</div><div id=\"rm-res\" style=\"color:rgba(28,10,0,.4);font-size:13px\">Пока ничего...</div></div>\n    <div style=\"display:flex;gap:7px;flex-wrap:wrap\">\n      <button class=\"btn btn-p\" onclick=\"addToShowcase()\">Добавить в витрину</button>\n      <button class=\"btn btn-s\" onclick=\"tryExp()\">Эксперимент 🧪</button>\n      <button class=\"btn btn-o\" onclick=\"clearTable()\">Очистить</button>\n    </div>\n  </div>\n  <div class=\"panel\">\n    <h3>Витрина</h3>\n    <button class=\"btn btn-o\" id=\"rec-book-btn\" onclick=\"openRB()\">📖 Книга рецептов</button>\n    <div id=\"budget-bar\">\n      <div>Бюджет: <strong id=\"bleft\">500 ₽</strong></div>\n      <div id=\"bprog\"><div id=\"bfill\" style=\"width:0%\"></div></div>\n    </div>\n    <div id=\"sc-list\"></div>\n    <div id=\"sc-empty\" style=\"color:rgba(28,10,0,.4);font-size:13px;text-align:center;padding:18px\">Витрина пуста</div>\n    <div style=\"margin-top:10px\"><button class=\"btn btn-p\" style=\"width:100%\" onclick=\"openBakery()\">Открыть кофейню ☀️</button></div>\n    <div style=\"margin-top:8px;font-size:11px;color:rgba(28,10,0,.4)\">Позиций: <span id=\"cap-used\">0</span>/20</div>\n  </div>\n</div>\n\n<!-- DAY -->\n<div id=\"phase-day\">\n  <div class=\"panel\" style=\"overflow-y:auto;max-height:calc(100vh - 140px)\">\n    <h3>Витрина</h3>\n    <div id=\"day-sc\"></div>\n    <div style=\"margin-top:10px;padding:9px;background:var(--cream);border-radius:9px\">\n      <div style=\"font-size:11px;color:rgba(28,10,0,.5)\">Выручка</div>\n      <div id=\"day-earned\" style=\"font-size:22px;font-weight:700;color:var(--caramel)\">0 ₽</div>\n    </div>\n    <div style=\"margin-top:8px\"><button class=\"btn btn-o\" style=\"width:100%;font-size:12px\" onclick=\"endDay()\">Закрыть кофейню 🌙</button></div>\n  </div>\n  <div>\n    <div class=\"panel\" style=\"padding:10px\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:8px\">\n        <h3 style=\"margin:0;font-size:14px\">Зал кофейни</h3>\n        <div id=\"day-timer\">00:00</div>\n      </div>\n      <div id=\"canvas-wrap\">\n        <canvas id=\"gc\" width=\"760\" height=\"420\"></canvas>\n      </div>\n      <div id=\"cust-info\">Ждём первых гостей...</div>\n      <div id=\"sell-area\">\n        <button class=\"btn\" id=\"btn-sell\" onclick=\"sellToCust()\">Обслужить ✓</button>\n        <button class=\"btn\" id=\"btn-no\" onclick=\"rejectCust()\">Нет в наличии ✗</button>\n        <button class=\"btn btn-o\" id=\"btn-auto\" onclick=\"toggleAuto()\">Авто: ВЫКЛ</button>\n      </div>\n      <div id=\"queue-row\">\n        <span style=\"font-size:11px;color:rgba(28,10,0,.5)\">Очередь:</span>\n        <div class=\"qd\" id=\"qd0\"></div><div class=\"qd\" id=\"qd1\"></div><div class=\"qd\" id=\"qd2\"></div><div class=\"qd\" id=\"qd3\"></div><div class=\"qd\" id=\"qd4\"></div>\n      </div>\n      <div id=\"day-log\"></div>\n    </div>\n  </div>\n</div>\n\n<!-- EVENING -->\n<div id=\"phase-evening\">\n  <div id=\"ev-title\">День завершён!</div>\n  <div id=\"ev-sub\">Итоги работы пекарни-кофейни</div>\n  <div class=\"sg\">\n    <div class=\"sc\"><div class=\"v\" id=\"ev-earned\">0 ₽</div><div class=\"l\">Выручка</div></div>\n    <div class=\"sc\"><div class=\"v\" id=\"ev-sold\">0</div><div class=\"l\">Продано</div></div>\n    <div class=\"sc\"><div class=\"v\" id=\"ev-rep\">0%</div><div class=\"l\">Репутация</div></div>\n  </div>\n  <div id=\"ts\" class=\"panel\" style=\"margin-bottom:14px\"><h3>Топ продаж</h3><div id=\"sales-bars\"></div></div>\n  <div class=\"lft-sec panel\" style=\"margin-bottom:14px\">\n    <h3>Остатки</h3>\n    <div id=\"lft-list\"></div>\n    <div style=\"display:flex;gap:8px;margin-top:10px\">\n      <button class=\"btn btn-s\" onclick=\"sellLeftovers()\">Продать −50%</button>\n      <button class=\"btn btn-o\" onclick=\"throwLeftovers()\">Выбросить</button>\n    </div>\n  </div>\n  <div id=\"unlock-sec\">\n    <div style=\"font-size:28px\">🎉</div>\n    <h3>Новый рецепт разблокирован!</h3>\n    <div id=\"unlock-name\"></div>\n    <p id=\"unlock-desc\" style=\"opacity:.85;font-size:13px;margin-top:4px\"></p>\n  </div>\n  <div style=\"text-align:center;margin-top:18px\">\n    <button class=\"btn btn-p\" style=\"font-size:15px;padding:13px 36px\" onclick=\"nextDay()\">Следующий день →</button>\n  </div>\n</div>\n\n<!-- DECOR -->\n<div id=\"phase-decor\">\n  <div class=\"panel\">\n    <h3>Интерьер кофейни</h3>\n    <canvas id=\"dc\" width=\"600\" height=\"340\"></canvas>\n    <div style=\"margin-top:8px;font-size:12px;color:rgba(28,10,0,.5)\">Уютный интерьер привлекает больше гостей</div>\n  </div>\n  <div class=\"panel\">\n    <h3>Магазин декора</h3>\n    <div id=\"decor-list\"></div>\n  </div>\n</div>\n\n<script>\n// ─── DATA ────────────────────────────────────────────────\nconst DAYS = ['Понедельник','Вторник','Среда','Четверг','Пятница','Суббота','Воскресенье'];\nconst WEATHERS = [\n  {name:'Солнечно',icon:'🌤'},{name:'Облачно',icon:'☁️'},{name:'Дождь',icon:'🌧'},\n  {name:'Жара',icon:'☀️'},{name:'Ветер',icon:'💨'}\n];\n\nconst INGS = [\n  {id:'flour',name:'Мука',clr:'#f5deb3'},{id:'butter',name:'Масло',clr:'#ffd700'},\n  {id:'milk',name:'Молоко',clr:'#e8f4f8'},{id:'sugar',name:'Сахар',clr:'#fff8dc'},\n  {id:'cinnamon',name:'Корица',clr:'#8b4513'},{id:'eggs',name:'Яйца',clr:'#ffa040'},\n  {id:'blueberry',name:'Черника',clr:'#6a0dad'},{id:'water',name:'Вода',clr:'#87ceeb'},\n  {id:'yeast',name:'Дрожжи',clr:'#d4b483'},{id:'chocolate',name:'Шоколад',clr:'#3d1c00'},\n  {id:'coffee',name:'Кофе',clr:'#4a2000'},{id:'foam',name:'Пена',clr:'#fffaf0'},\n  {id:'lemon',name:'Лимон',clr:'#ffe066'},\n];\n\nconst RECIPES = [\n  {id:'croissant',name:'Круассан',price:80,ings:['flour','butter','milk'],cat:'bakery'},\n  {id:'cinnamon_bun',name:'Булочка с корицей',price:65,ings:['flour','sugar','cinnamon'],cat:'bakery'},\n  {id:'muffin',name:'Маффин черничный',price:90,ings:['flour','eggs','blueberry'],cat:'bakery'},\n  {id:'baguette',name:'Багет',price:70,ings:['flour','water','yeast'],cat:'bakery'},\n  {id:'eclair',name:'Эклер',price:120,ings:['flour','eggs','chocolate'],cat:'bakery'},\n  {id:'espresso',name:'Эспрессо',price:90,ings:['coffee','water'],cat:'drink'},\n  {id:'cappuccino',name:'Капучино',price:140,ings:['coffee','milk','foam'],cat:'drink'},\n  {id:'latte',name:'Латте',price:150,ings:['coffee','milk','milk'],cat:'drink'},\n  {id:'lemonade',name:'Лимонад',price:80,ings:['lemon','water','sugar'],cat:'drink'},\n  {id:'almond_croissant',name:'Круассан с миндалём',price:110,ings:['flour','butter','milk'],cat:'bakery',locked:true},\n  {id:'honey_cake',name:'Торт медовик',price:200,ings:['flour','eggs','sugar'],cat:'bakery',locked:true},\n  {id:'matcha_latte',name:'Матча латте',price:170,ings:['coffee','milk','foam'],cat:'drink',locked:true},\n  {id:'recipe_of_day',name:'Авторский рецепт',price:130,ings:[],cat:'special',locked:true},\n  {id:'breakfast',name:'Меню завтрака',price:250,ings:['flour','eggs','butter'],cat:'special',locked:true},\n];\n\nconst CTYPES = [\n  {id:'student',name:'Студент',speed:1.2,patience:15,prefs:['espresso','baguette','cinnamon_bun'],tip:.05,clr:'#4a90d9',hair:'#3a2a1a',shirt:'#4a90d9'},\n  {id:'bizlady',name:'Бизнес-леди',speed:1.8,patience:12,prefs:['latte','cappuccino','croissant'],tip:.2,clr:'#2c3e50',hair:'#1a0a00',shirt:'#2c3e50'},\n  {id:'tourist',name:'Турист',speed:1.0,patience:25,prefs:null,tip:.15,clr:'#e67e22',hair:'#c0a060',shirt:'#e67e22'},\n  {id:'hipster',name:'Хипстер',speed:1.1,patience:20,prefs:['matcha_latte','eclair','recipe_of_day'],tip:.1,clr:'#8e44ad',hair:'#2c1a0a',shirt:'#8e44ad'},\n  {id:'granny',name:'Пенсионерка',speed:0.6,patience:30,prefs:['lemonade','baguette','cinnamon_bun'],tip:0,clr:'#7f8c8d',hair:'#ddd',shirt:'#9b59b6'},\n  {id:'mom',name:'Мама с коляской',speed:0.8,patience:22,prefs:['latte','croissant','muffin'],tip:.05,clr:'#e91e8c',hair:'#8b4513',shirt:'#e91e8c'},\n];\n\nconst DECORS = [\n  {id:'table',name:'Уютный столик',desc:'+5% туристов',price:300,icon:'🪑'},\n  {id:'painting',name:'Картина',desc:'+10% хипстеров',price:500,icon:'🖼'},\n  {id:'plant',name:'Растение',desc:'+2% репутация',price:200,icon:'🌿'},\n  {id:'lighting',name:'Тёплый свет',desc:'+5% все клиенты',price:800,icon:'💡'},\n  {id:'menu_board',name:'Меловая доска',desc:'+8% продажи',price:400,icon:'📋'},\n  {id:'jazz',name:'Живая музыка',desc:'+30% терпение',price:1200,icon:'🎵'},\n];\n\n// ─── STATE ────────────────────────────────────────────────\nlet S = {\n  day:1, money:500, rep:50, weather:WEATHERS[0],\n  showcase:{}, table:[], dayStats:{earned:0,sold:{},unhappy:0,exp:0},\n  unlocked:['croissant','cinnamon_bun','muffin','baguette','eclair','espresso','cappuccino','latte','lemonade'],\n  decor:{}, totalStats:{croissants:0,maxDay:0,repDays:0,day5:false,exps:0},\n  autoSell:false, dayEarned:0,\n};\nlet budgetUsed = 0;\n\n// ─── AUDIO ───────────────────────────────────────────────\nlet aCtx;\nfunction ac(){if(!aCtx)aCtx=new(window.AudioContext||window.webkitAudioContext)();return aCtx;}\nfunction tone(f,t='sine',d=.15,v=.25){try{const c=ac(),o=c.createOscillator(),g=c.createGain();o.connect(g);g.connect(c.destination);o.type=t;o.frequency.value=f;g.gain.setValueAtTime(v,c.currentTime);g.gain.exponentialRampToValueAtTime(.001,c.currentTime+d);o.start();o.stop(c.currentTime+d);}catch(e){}}\nfunction ding(){tone(880);setTimeout(()=>tone(1100,'sine',.1),80);}\nfunction boop(){tone(220,'sawtooth',.2,.2);}\nfunction brew(){[300,320,310,330].forEach((f,i)=>setTimeout(()=>tone(f,'sine',.1,.12),i*110));}\nfunction fanfare(){[440,550,660,880].forEach((f,i)=>setTimeout(()=>tone(f,'sine',.2,.28),i*140));}\n\n// ─── SAVE/LOAD ────────────────────────────────────────────\nasync function save(){\n  const p=JSON.stringify(S);\n  localStorage.setItem('lf',p);\n  try{await fetch('/api/save',{method:'POST',headers:{'Content-Type':'application/json'},body:p});}catch(e){}\n}\nasync function load(){\n  try{const r=await fetch('/api/load');if(r.ok){const d=await r.json();if(d&&d.day){Object.assign(S,d);return;}}}catch(e){}\n  const s=localStorage.getItem('lf');if(s){try{Object.assign(S,JSON.parse(s));}catch(e){}}\n}\n\n// ─── NOTIFY ──────────────────────────────────────────────\nfunction notify(msg,t='i'){\n  const w=document.getElementById('nw'),el=document.createElement('div');\n  el.className=`notif ${t}`;el.textContent=msg;w.appendChild(el);\n  setTimeout(()=>{el.classList.add('out');setTimeout(()=>el.remove(),320);},2400);\n}\n\n// ─── SVG ICONS ───────────────────────────────────────────\nfunction ingIcon(id,size=28){\n  const icons={\n    flour:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"8\" y=\"10\" width=\"16\" height=\"14\" rx=\"2\" fill=\"#f5deb3\" stroke=\"#d4b080\" stroke-width=\"1.5\"/><ellipse cx=\"16\" cy=\"10\" rx=\"8\" ry=\"4\" fill=\"#e8c87a\"/><line x1=\"12\" y1=\"14\" x2=\"20\" y2=\"14\" stroke=\"#d4b080\" stroke-width=\"1\"/><line x1=\"12\" y1=\"18\" x2=\"20\" y2=\"18\" stroke=\"#d4b080\" stroke-width=\"1\"/></svg>`,\n    butter:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"6\" y=\"12\" width=\"20\" height=\"10\" rx=\"3\" fill=\"#ffd700\" stroke=\"#e6b800\" stroke-width=\"1.5\"/><rect x=\"6\" y=\"12\" width=\"20\" height=\"4\" rx=\"3\" fill=\"#ffe566\"/></svg>`,\n    milk:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><path d=\"M11 8 L9 24 Q9 26 16 26 Q23 26 23 24 L21 8Z\" fill=\"#e8f4f8\" stroke=\"#b0d0e0\" stroke-width=\"1.5\"/><path d=\"M10 8 L12 5 H20 L22 8Z\" fill=\"#c8e8f0\"/><ellipse cx=\"16\" cy=\"16\" rx=\"4\" ry=\"2\" fill=\"rgba(255,255,255,0.5)\"/></svg>`,\n    sugar:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"9\" y=\"11\" width=\"14\" height=\"13\" rx=\"2\" fill=\"#fff8dc\" stroke=\"#e8d890\" stroke-width=\"1.5\"/><circle cx=\"13\" cy=\"16\" r=\"1.5\" fill=\"#fff\"/><circle cx=\"16\" cy=\"14\" r=\"1\" fill=\"#fff\"/><circle cx=\"19\" cy=\"17\" r=\"1.5\" fill=\"#fff\"/><circle cx=\"14\" cy=\"19\" r=\"1\" fill=\"#fff\"/></svg>`,\n    cinnamon:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"12\" y=\"6\" width=\"8\" height=\"20\" rx=\"4\" fill=\"#8b4513\" stroke=\"#6b3010\" stroke-width=\"1\"/><path d=\"M14 10 Q18 12 14 16 Q18 18 14 22\" fill=\"none\" stroke=\"#a0522d\" stroke-width=\"1\"/></svg>`,\n    eggs:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><ellipse cx=\"16\" cy=\"17\" rx=\"7\" ry=\"9\" fill=\"#ffa040\" stroke=\"#e08030\" stroke-width=\"1.5\"/><ellipse cx=\"16\" cy=\"17\" rx=\"4\" ry=\"5\" fill=\"#ffe0a0\"/></svg>`,\n    blueberry:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><circle cx=\"16\" cy=\"16\" r=\"9\" fill=\"#6a0dad\" stroke=\"#500a9a\" stroke-width=\"1.5\"/><circle cx=\"13\" cy=\"13\" r=\"3\" fill=\"#8b2fd4\"/><circle cx=\"19\" cy=\"14\" r=\"2.5\" fill=\"#7a1ac0\"/><circle cx=\"15\" cy=\"19\" r=\"3\" fill=\"#7a1ac0\"/><circle cx=\"16\" cy=\"12\" r=\"1.5\" fill=\"rgba(255,255,255,0.3)\"/></svg>`,\n    water:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><path d=\"M16 6 Q22 14 22 19 A6 6 0 0 1 10 19 Q10 14 16 6Z\" fill=\"#87ceeb\" stroke=\"#5aabce\" stroke-width=\"1.5\"/><path d=\"M13 20 Q16 22 19 20\" fill=\"none\" stroke=\"rgba(255,255,255,0.6)\" stroke-width=\"1.5\" stroke-linecap=\"round\"/></svg>`,\n    yeast:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"8\" y=\"10\" width=\"16\" height=\"12\" rx=\"3\" fill=\"#d4b483\" stroke=\"#b09060\" stroke-width=\"1.5\"/><circle cx=\"12\" cy=\"14\" r=\"2\" fill=\"#e8c87a\"/><circle cx=\"16\" cy=\"17\" r=\"2.5\" fill=\"#e8c87a\"/><circle cx=\"20\" cy=\"14\" r=\"1.5\" fill=\"#e8c87a\"/></svg>`,\n    chocolate:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><rect x=\"6\" y=\"9\" width=\"20\" height=\"14\" rx=\"3\" fill=\"#3d1c00\" stroke=\"#2a1200\" stroke-width=\"1.5\"/><line x1=\"6\" y1=\"14\" x2=\"26\" y2=\"14\" stroke=\"#5c3317\" stroke-width=\"1.5\"/><line x1=\"16\" y1=\"9\" x2=\"16\" y2=\"23\" stroke=\"#5c3317\" stroke-width=\"1.5\"/><rect x=\"8\" y=\"11\" width=\"7\" height=\"2\" rx=\"1\" fill=\"#5c3317\"/><rect x=\"17\" y=\"16\" width=\"7\" height=\"2\" rx=\"1\" fill=\"#5c3317\"/></svg>`,\n    coffee:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><ellipse cx=\"16\" cy=\"20\" rx=\"8\" ry=\"6\" fill=\"#4a2000\"/><ellipse cx=\"16\" cy=\"18\" rx=\"8\" ry=\"4\" fill=\"#6b3010\"/><path d=\"M13 10 Q13 6 15 8 Q17 6 17 10\" fill=\"none\" stroke=\"#aaa\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/><path d=\"M17 9 Q17 5 19 7 Q21 5 21 9\" fill=\"none\" stroke=\"#aaa\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/></svg>`,\n    foam:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><ellipse cx=\"16\" cy=\"18\" rx=\"10\" ry=\"5\" fill=\"#fffaf0\" stroke=\"#e8e0d0\" stroke-width=\"1\"/><circle cx=\"11\" cy=\"17\" r=\"3\" fill=\"#fff\"/><circle cx=\"16\" cy=\"15\" r=\"4\" fill=\"#fff\"/><circle cx=\"21\" cy=\"17\" r=\"3\" fill=\"#fff\"/><circle cx=\"14\" cy=\"20\" r=\"2.5\" fill=\"#fff\"/><circle cx=\"19\" cy=\"20\" r=\"2\" fill=\"#fff\"/></svg>`,\n    lemon:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><ellipse cx=\"16\" cy=\"16\" rx=\"10\" ry=\"8\" fill=\"#ffe066\" stroke=\"#e6c800\" stroke-width=\"1.5\"/><ellipse cx=\"16\" cy=\"16\" rx=\"10\" ry=\"8\" fill=\"none\" stroke=\"#ffd700\" stroke-width=\"2\" stroke-dasharray=\"3,3\"/><circle cx=\"16\" cy=\"16\" r=\"4\" fill=\"#fff8a0\"/></svg>`,\n  };\n  return icons[id]||`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 32 32\"><circle cx=\"16\" cy=\"16\" r=\"10\" fill=\"#ccc\"/></svg>`;\n}\n\nfunction recipeIcon(id,size=36){\n  const icons={\n    croissant:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M8 32 C10 16 20 8 34 10 C30 18 18 24 8 32Z\" fill=\"#f4c777\" stroke=\"#c8873a\" stroke-width=\"2\"/><path d=\"M10 30 C13 18 22 12 30 12\" fill=\"none\" stroke=\"#e8a850\" stroke-width=\"1.5\" stroke-linecap=\"round\"/><path d=\"M12 26 C15 20 22 16 28 15\" fill=\"none\" stroke=\"#e8a850\" stroke-width=\"1\" stroke-linecap=\"round\"/></svg>`,\n    cinnamon_bun:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><circle cx=\"20\" cy=\"20\" r=\"13\" fill=\"#c8873a\"/><path d=\"M12 20 Q16 12 20 20 Q24 28 28 20\" fill=\"none\" stroke=\"#8b4513\" stroke-width=\"2.5\" stroke-linecap=\"round\"/><path d=\"M13 22 Q17 14 20 22\" fill=\"none\" stroke=\"#8b4513\" stroke-width=\"1.5\" stroke-linecap=\"round\"/></svg>`,\n    muffin:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"12\" y=\"20\" width=\"16\" height=\"14\" rx=\"3\" fill=\"#c8873a\"/><ellipse cx=\"20\" cy=\"20\" rx=\"10\" ry=\"6\" fill=\"#d4956a\"/><circle cx=\"16\" cy=\"23\" r=\"2.5\" fill=\"#4b0082\"/><circle cx=\"22\" cy=\"27\" r=\"2.5\" fill=\"#4b0082\"/><circle cx=\"25\" cy=\"22\" r=\"2\" fill=\"#4b0082\"/></svg>`,\n    baguette:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><ellipse cx=\"20\" cy=\"20\" rx=\"15\" ry=\"6\" fill=\"#e8c87a\" transform=\"rotate(-25 20 20)\" stroke=\"#c89840\" stroke-width=\"1.5\"/><line x1=\"14\" y1=\"14\" x2=\"22\" y2=\"26\" stroke=\"#c89840\" stroke-width=\"1.5\"/><line x1=\"18\" y1=\"12\" x2=\"26\" y2=\"24\" stroke=\"#c89840\" stroke-width=\"1\"/></svg>`,\n    eclair:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"6\" y=\"14\" width=\"28\" height=\"14\" rx=\"7\" fill=\"#d4956a\"/><rect x=\"6\" y=\"14\" width=\"28\" height=\"7\" rx=\"7\" fill=\"#2c1000\"/><path d=\"M10 18 Q20 14 30 18\" fill=\"none\" stroke=\"rgba(255,255,255,0.2)\" stroke-width=\"1.5\"/></svg>`,\n    espresso:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M13 17 L27 17 L25 32 L15 32Z\" fill=\"#5c3317\"/><ellipse cx=\"20\" cy=\"17\" rx=\"7\" ry=\"3\" fill=\"#3d1c00\"/><path d=\"M15 10 Q15 5 17 8 Q19 5 19 10\" fill=\"none\" stroke=\"#aaa\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/><path d=\"M21 9 Q21 4 23 7\" fill=\"none\" stroke=\"#aaa\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/></svg>`,\n    cappuccino:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M10 18 L30 18 L28 33 L12 33Z\" fill=\"#c4956a\"/><ellipse cx=\"20\" cy=\"18\" rx=\"10\" ry=\"4\" fill=\"#fff8f0\"/><circle cx=\"16\" cy=\"17\" r=\"3\" fill=\"#fff\"/><circle cx=\"22\" cy=\"16\" r=\"3.5\" fill=\"#fff\"/><circle cx=\"24\" cy=\"19\" r=\"2.5\" fill=\"#fff\"/><path d=\"M15 10 Q15 5 17 8\" fill=\"none\" stroke=\"#bbb\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/><path d=\"M21 10 Q21 5 23 8\" fill=\"none\" stroke=\"#bbb\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/></svg>`,\n    latte:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"9\" y=\"16\" width=\"22\" height=\"18\" rx=\"4\" fill=\"#d4a87a\"/><ellipse cx=\"20\" cy=\"16\" rx=\"11\" ry=\"4\" fill=\"#fff8f0\"/><path d=\"M14 15 Q20 12 26 15\" fill=\"none\" stroke=\"rgba(200,135,58,0.5)\" stroke-width=\"1.5\"/><path d=\"M14 12 Q14 7 16 10\" fill=\"none\" stroke=\"#bbb\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/></svg>`,\n    lemonade:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"11\" y=\"12\" width=\"18\" height=\"22\" rx=\"4\" fill=\"#fff8aa\" stroke=\"#e8d800\" stroke-width=\"1.5\"/><ellipse cx=\"20\" cy=\"12\" rx=\"9\" ry=\"3\" fill=\"#ffe066\"/><circle cx=\"16\" cy=\"20\" r=\"3\" fill=\"#ffe066\" opacity=\".8\"/><circle cx=\"22\" cy=\"17\" r=\"2.5\" fill=\"#ffe066\" opacity=\".8\"/><circle cx=\"18\" cy=\"26\" r=\"2\" fill=\"#ffe066\" opacity=\".8\"/><line x1=\"24\" y1=\"8\" x2=\"24\" y2=\"14\" stroke=\"#4a7c59\" stroke-width=\"2.5\" stroke-linecap=\"round\"/></svg>`,\n    almond_croissant:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><path d=\"M8 32 C10 16 20 8 34 10 C30 18 18 24 8 32Z\" fill=\"#e8c87a\" stroke=\"#c8873a\" stroke-width=\"2\"/><line x1=\"18\" y1=\"15\" x2=\"22\" y2=\"22\" stroke=\"#fff\" stroke-width=\"2\" stroke-linecap=\"round\"/><line x1=\"14\" y1=\"22\" x2=\"24\" y2=\"20\" stroke=\"#fff\" stroke-width=\"1.5\" stroke-linecap=\"round\"/></svg>`,\n    honey_cake:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"7\" y=\"20\" width=\"26\" height=\"14\" rx=\"3\" fill=\"#c8873a\"/><rect x=\"7\" y=\"14\" width=\"26\" height=\"8\" rx=\"3\" fill=\"#e8c87a\"/><path d=\"M14 14 Q14 8 20 11 Q26 8 26 14\" fill=\"#ffd700\"/><circle cx=\"20\" cy=\"11\" r=\"3\" fill=\"#ffc000\"/></svg>`,\n    matcha_latte:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"9\" y=\"16\" width=\"22\" height=\"18\" rx=\"4\" fill=\"#4a7c59\"/><ellipse cx=\"20\" cy=\"16\" rx=\"11\" ry=\"4\" fill=\"#fff8f0\"/><circle cx=\"16\" cy=\"15\" r=\"3\" fill=\"#fff\"/><circle cx=\"23\" cy=\"14\" r=\"3.5\" fill=\"#fff\"/><path d=\"M14 12 Q14 7 16 10\" fill=\"none\" stroke=\"#bbb\" stroke-width=\"1.5\" stroke-linecap=\"round\" class=\"sp\"/></svg>`,\n    recipe_of_day:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><polygon points=\"20,4 23,15 35,15 25,22 29,33 20,26 11,33 15,22 5,15 17,15\" fill=\"#9b59b6\" stroke=\"#7d3c98\" stroke-width=\"1\"/></svg>`,\n    breakfast:`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><rect x=\"5\" y=\"10\" width=\"30\" height=\"22\" rx=\"4\" fill=\"#e8c87a\" stroke=\"#c8873a\" stroke-width=\"2\"/><line x1=\"5\" y1=\"18\" x2=\"35\" y2=\"18\" stroke=\"#c8873a\" stroke-width=\"2\"/><line x1=\"18\" y1=\"10\" x2=\"18\" y2=\"32\" stroke=\"#c8873a\" stroke-width=\"2\"/><circle cx=\"11\" cy=\"24\" r=\"4\" fill=\"#ffa040\"/></svg>`,\n  };\n  return icons[id]||`<svg width=\"${size}\" height=\"${size}\" viewBox=\"0 0 40 40\"><circle cx=\"20\" cy=\"20\" r=\"14\" fill=\"#ccc\"/></svg>`;\n}\n\n// ─── HEADER ──────────────────────────────────────────────\nfunction updateHdr(){\n  document.getElementById('hdr-day').textContent=`День ${S.day} · ${DAYS[(S.day-1)%7]}`;\n  document.getElementById('hdr-wx').textContent=`${S.weather.icon} ${S.weather.name}`;\n  document.getElementById('hdr-money').textContent=`${S.money} ₽`;\n  document.getElementById('rep-pct').textContent=`${Math.round(S.rep)}%`;\n  document.getElementById('rep-fill').style.width=`${Math.min(100,S.rep)}%`;\n}\n\n// ─── PHASE SWITCH ─────────────────────────────────────────\nfunction switchPhase(p){\n  ['morning','day','evening','decor'].forEach(x=>{\n    const el=document.getElementById(`phase-${x}`);\n    el.classList.remove('active');el.style.display='none';\n  });\n  document.querySelectorAll('.nb').forEach(b=>b.classList.remove('active'));\n  document.getElementById(`nav-${p}`).classList.add('active');\n  const ph=document.getElementById(`phase-${p}`);\n  ph.style.display=p==='evening'?'block':'grid';\n  ph.classList.add('active');\n  if(p==='morning')renderMorning();\n  if(p==='day')initDay();\n  if(p==='evening')renderEvening();\n  if(p==='decor')renderDecor();\n}\n\n// ─── MORNING ─────────────────────────────────────────────\nfunction renderMorning(){renderIngs();renderSidebar();updateBudget();}\n\nfunction renderIngs(){\n  const l=document.getElementById('ing-list');l.innerHTML='';\n  INGS.forEach(ing=>{\n    const d=document.createElement('div');d.className='ing-item';d.draggable=true;d.dataset.id=ing.id;\n    d.innerHTML=ingIcon(ing.id,24)+`<span>${ing.name}</span>`;\n    d.addEventListener('dragstart',e=>{e.dataTransfer.setData('text/plain',ing.id);d.style.opacity='.4';});\n    d.addEventListener('dragend',()=>d.style.opacity='1');\n    l.appendChild(d);\n  });\n}\n\nconst dz=document.getElementById('drop-zone');\ndz.addEventListener('dragover',e=>{e.preventDefault();dz.classList.add('over');});\ndz.addEventListener('dragleave',()=>dz.classList.remove('over'));\ndz.addEventListener('drop',e=>{\n  e.preventDefault();dz.classList.remove('over');\n  const id=e.dataTransfer.getData('text/plain');\n  if(id&&S.table.length<5){S.table.push(id);brew();renderTable();checkMatch();}\n});\n\nfunction renderTable(){\n  const hint=document.getElementById('drop-hint');\n  dz.querySelectorAll('.di').forEach(x=>x.remove());\n  hint.style.display=S.table.length?'none':'flex';\n  S.table.forEach((id,i)=>{\n    const ing=INGS.find(x=>x.id===id);if(!ing)return;\n    const el=document.createElement('div');el.className='di';\n    el.innerHTML=ingIcon(id,28)+`<span>${ing.name}</span>`;\n    el.title='Кликните чтобы убрать';\n    el.onclick=()=>{S.table.splice(i,1);renderTable();checkMatch();};\n    dz.appendChild(el);\n  });\n}\n\nfunction checkMatch(){\n  const res=document.getElementById('rm-res'),exp=document.getElementById('exp-hint');\n  const sorted=[...S.table].sort();\n  if(!sorted.length){res.innerHTML='<span style=\"opacity:.4\">Пока ничего...</span>';exp.style.display='none';return;}\n  let m=null;\n  for(const r of RECIPES){\n    if(!S.unlocked.includes(r.id))continue;\n    if(JSON.stringify([...r.ings].sort())===JSON.stringify(sorted)){m=r;break;}\n  }\n  if(m){res.innerHTML=`<div class=\"rm-card\">${recipeIcon(m.id,28)}<strong>${m.name}</strong><span>${m.price} ₽</span></div>`;exp.style.display='none';}\n  else if(sorted.length>=2){res.innerHTML='<span style=\"color:rgba(28,10,0,.45);font-size:13px\">Неизвестная комбинация</span>';exp.style.display='block';}\n  else{res.innerHTML='<span style=\"opacity:.4\">Добавьте ещё...</span>';exp.style.display='none';}\n}\n\nfunction clearTable(){S.table=[];renderTable();checkMatch();}\n\nfunction tryExp(){\n  if(S.table.length<2){notify('Нужно минимум 2 ингредиента!','b');return;}\n  S.dayStats.exp++;S.totalStats.exps++;\n  if(Math.random()>.4){\n    const lu=RECIPES.filter(r=>!S.unlocked.includes(r.id))[0];\n    fanfare();\n    if(lu&&Math.random()>.5){S.unlocked.push(lu.id);notify(`Открыт рецепт: ${lu.name}!`,'g');}\n    else{notify('Эксперимент удался! +50₽','g');S.money+=50;updateHdr();}\n  }else{boop();notify('Эксперимент не удался...','b');}\n  clearTable();save();\n}\n\nfunction addToShowcase(){\n  const sorted=[...S.table].sort();\n  if(!sorted.length){notify('Стол пуст!','b');return;}\n  let m=null;\n  for(const r of RECIPES){\n    if(!S.unlocked.includes(r.id))continue;\n    if(JSON.stringify([...r.ings].sort())===JSON.stringify(sorted)){m=r;break;}\n  }\n  if(!m){notify('Рецепт не распознан. Попробуйте эксперимент!','i');return;}\n  const total=Object.values(S.showcase).reduce((a,b)=>a+b,0);\n  if(total>=20){notify('Витрина полна!','b');return;}\n  const cost=Math.round(m.price*.3);\n  if(S.money<cost){notify('Недостаточно денег!','b');return;}\n  S.showcase[m.id]=(S.showcase[m.id]||0)+1;\n  S.money-=cost;budgetUsed+=cost;\n  clearTable();renderSidebar();updateBudget();updateHdr();ding();\n  notify(`${m.name} добавлен в витрину`,'g');\n}\n\nfunction renderSidebar(){\n  const l=document.getElementById('sc-list'),e=document.getElementById('sc-empty');\n  l.innerHTML='';\n  const items=Object.keys(S.showcase).filter(k=>S.showcase[k]>0);\n  e.style.display=items.length?'none':'block';\n  items.forEach(id=>{\n    const r=RECIPES.find(x=>x.id===id);if(!r)return;\n    const d=document.createElement('div');d.className='sc-item';\n    d.innerHTML=`${recipeIcon(id,26)}<span class=\"iname\">${r.name}</span><span class=\"iprice\">${r.price}₽</span>\n    <div class=\"qty\"><button class=\"qb\" onclick=\"chQty('${id}',-1)\">−</button><span class=\"qv\">${S.showcase[id]}</span><button class=\"qb\" onclick=\"chQty('${id}',1)\">+</button></div>`;\n    l.appendChild(d);\n  });\n  document.getElementById('cap-used').textContent=Object.values(S.showcase).reduce((a,b)=>a+b,0);\n}\n\nfunction chQty(id,d){\n  const r=RECIPES.find(x=>x.id===id),c=Math.round(r.price*.3),n=(S.showcase[id]||0)+d;\n  if(n<=0){delete S.showcase[id];}\n  else if(n>20){notify('Максимум 20','b');return;}\n  else{\n    if(d>0){if(S.money<c){notify('Недостаточно денег!','b');return;}S.money-=c;budgetUsed+=c;}\n    else{S.money+=c;budgetUsed-=c;}\n    S.showcase[id]=n;\n  }\n  renderSidebar();updateBudget();updateHdr();\n}\n\nfunction updateBudget(){\n  document.getElementById('bleft').textContent=`${S.money} ₽`;\n  document.getElementById('bfill').style.width=`${Math.min(100,budgetUsed/(500+(S.day-1)*100)*100)}%`;\n}\n\nfunction openBakery(){\n  if(!Object.keys(S.showcase).length){notify('Витрина пуста!','b');return;}\n  S.dayStats={earned:0,sold:{},unhappy:0,exp:0};S.dayEarned=0;\n  switchPhase('day');\n}\n\n// ─── RECIPE BOOK ─────────────────────────────────────────\nfunction openRB(){\n  ['bakery','drinks','special'].forEach(t=>document.getElementById(`rb-${t}`).innerHTML='');\n  const spec=RECIPES.filter(r=>r.cat==='special');\n  document.getElementById('rb-special-hdr').style.display=spec.length?'block':'none';\n  RECIPES.forEach(r=>{\n    const unlk=S.unlocked.includes(r.id);\n    const el=document.createElement('div');el.className=`rb-card ${unlk?'unlocked':'locked'}`;\n    const ings=r.ings.map(i=>{const x=INGS.find(g=>g.id===i);return x?x.name:'?';}).join(' + ')||'???';\n    el.innerHTML=`${recipeIcon(r.id,40)}<div class=\"rc-name\">${unlk?r.name:'???'}</div><div class=\"rc-price\">${unlk?r.price+'₽':'🔒'}</div><div class=\"rc-ings\">${unlk?ings:'Неизвестно'}</div>`;\n    const target=r.cat==='bakery'?'rb-bakery':r.cat==='drink'?'rb-drinks':'rb-special';\n    document.getElementById(target).appendChild(el);\n  });\n  document.getElementById('rb-overlay').classList.add('active');\n}\nfunction closeRB(){document.getElementById('rb-overlay').classList.remove('active');}\n\n// ─── DAY PHASE ───────────────────────────────────────────\nconst cv=document.getElementById('gc');\nconst ctx=cv.getContext('2d');\nlet custs=[],queue=[],dayRunning=false,dayTime=0,lastSpawn=0,nextSpawnIn=10;\nlet activeCust=null,animId=null,bobT=0;\n\n// TABLE SEATS: 3 tables × 2 seats each\nconst TABLE_SEATS=[\n  {x:120,y:280},{x:155,y:280},\n  {x:240,y:290},{x:275,y:290},\n  {x:355,y:275},{x:390,y:275},\n];\nconst seatOccupied={};\n\nclass Cust{\n  constructor(){\n    const w=[3,2,3,2,3,1];let roll=Math.random()*14,acc=0,idx=0;\n    for(let i=0;i<w.length;i++){acc+=w[i];if(roll<acc){idx=i;break;}}\n    this.type=CTYPES[idx];\n    const avail=Object.keys(S.showcase).filter(k=>S.showcase[k]>0);\n    if(!avail.length){this.want=null;}\n    else if(this.type.prefs){\n      const pf=this.type.prefs.filter(p=>avail.includes(p));\n      this.want=pf.length?pf[Math.floor(Math.random()*pf.length)]:avail[Math.floor(Math.random()*avail.length)];\n    }else{this.want=avail[Math.floor(Math.random()*avail.length)];}\n    this.x=-60;this.y=218;\n    this.targetX=470+Math.random()*20;\n    this.state='walking';// walking|waiting|served|eating|leaving\n    this.patience=this.type.patience*(S.decor['jazz']?1.3:1);\n    this.waitTime=0;this.id=Math.random();\n    this.seatIdx=-1;this.eatTime=0;this.eatDur=8+Math.random()*8;\n    this.flip=false;\n  }\n  wantName(){const r=RECIPES.find(x=>x.id===this.want);return r?r.name:'что-нибудь';}\n}\n\nfunction initDay(){\n  custs=[];queue=[];dayRunning=true;dayTime=0;lastSpawn=0;\n  nextSpawnIn=8+Math.random()*7;activeCust=null;S.dayEarned=0;\n  Object.keys(seatOccupied).forEach(k=>delete seatOccupied[k]);\n  document.getElementById('day-earned').textContent='0 ₽';\n  document.getElementById('day-log').innerHTML='';\n  renderDaySC();\n  // First customer arrives early\n  setTimeout(spawnCust, 2000);\n  if(animId)cancelAnimationFrame(animId);\n  let last=null;\n  function loop(ts){\n    if(!dayRunning)return;\n    if(!last)last=ts;\n    const dt=Math.min((ts-last)/1000,.05);last=ts;\n    bobT+=dt*3;dayTime+=dt;lastSpawn+=dt;\n    // timer\n    const mm=String(Math.floor(dayTime/60)).padStart(2,'0'),ss=String(Math.floor(dayTime%60)).padStart(2,'0');\n    document.getElementById('day-timer').textContent=`${mm}:${ss}`;\n    // spawn\n    if(lastSpawn>=nextSpawnIn&&custs.filter(c=>c.state==='waiting').length<5){\n      spawnCust();\n      if(Math.random()<.15){setTimeout(spawnCust,2000);setTimeout(spawnCust,4000);}\n      lastSpawn=0;nextSpawnIn=8+Math.random()*7;\n    }\n    // update\n    custs.forEach(c=>{\n      if(c.state==='walking'){\n        c.x+=c.type.speed*90*dt*(c.flip?-1:1);\n        if(!c.flip&&c.x>=c.targetX){c.state='waiting';queue.push(c);updateQD();}\n        if(c.flip&&c.x>cv.width+80){c.state='gone';}\n      }\n      if(c.state==='waiting'){\n        c.waitTime+=dt;\n        if(c.waitTime>c.patience){c.state='leaving';leaveAngry(c);}\n      }\n      if(c.state==='served'){\n        // walk to seat\n        const seat=TABLE_SEATS[c.seatIdx];\n        if(seat){\n          c.flip=true;\n          const tx=seat.x;\n          const speed=c.type.speed*80*dt;\n          if(Math.abs(c.x-tx)<speed+2){c.x=tx;c.y=seat.y-40;c.state='eating';c.eatTime=0;}\n          else if(c.x>tx){c.x-=speed;}else{c.x+=speed;}\n        }else{c.state='eating';c.eatTime=0;}\n      }\n      if(c.state==='eating'){\n        c.eatTime+=dt;\n        if(c.eatTime>=c.eatDur){c.state='leaving_seat';}\n      }\n      if(c.state==='leaving_seat'){\n        seatOccupied[c.seatIdx]=false;\n        c.flip=true;c.state='walking';c.targetX=cv.width+100;\n      }\n      if(c.state==='leaving'){c.x+=c.type.speed*70*dt;if(c.x>cv.width+80)c.state='gone';}\n    });\n    custs=custs.filter(c=>c.state!=='gone');\n    queue=queue.filter(c=>c.state==='waiting');\n    updateQD();\n    if(S.autoSell&&queue.length){\n      const f=queue[0];\n      if(f&&f.want&&S.showcase[f.want]>0){activeCust=f;setTimeout(()=>{if(activeCust===f)doSell();},200);}\n    }\n    if(!activeCust&&queue.length){activeCust=queue[0];updateCustUI();}\n    else if(!queue.length){activeCust=null;document.getElementById('cust-info').textContent='Ждём гостей...';}\n    draw();\n    animId=requestAnimationFrame(loop);\n  }\n  animId=requestAnimationFrame(loop);\n}\n\nfunction spawnCust(){const c=new Cust();custs.push(c);addLog(`Пришёл ${c.type.name} → хочет ${c.wantName()}`,'n');}\n\nfunction leaveAngry(c){\n  S.rep=Math.max(0,S.rep-2);S.dayStats.unhappy++;\n  addLog(`${c.type.name} ушёл недовольным!`,'b');\n  queue=queue.filter(x=>x!==c);if(activeCust===c)activeCust=null;\n  updateQD();updateHdr();boop();\n}\n\nfunction updateCustUI(){\n  if(!activeCust)return;\n  document.getElementById('cust-info').textContent=`${activeCust.type.name} хочет: ${activeCust.wantName()}`;\n}\n\nfunction sellToCust(){\n  if(!activeCust||activeCust.state!=='waiting'){notify('Нет клиента у стойки','b');return;}\n  doSell();\n}\nfunction doSell(){\n  const c=activeCust;\n  const r=RECIPES.find(x=>x.id===c.want);\n  if(!r||!S.showcase[c.want]||S.showcase[c.want]<=0){notify('Закончилось!','b');rejectCust();return;}\n  S.showcase[c.want]--;\n  const tip=Math.round(r.price*c.type.tip),earned=r.price+tip;\n  S.money+=earned;S.dayEarned+=earned;S.dayStats.earned+=earned;\n  S.dayStats.sold[c.want]=(S.dayStats.sold[c.want]||0)+1;\n  S.totalStats.croissants+=(c.want==='croissant'?1:0);\n  // find free seat\n  const si=TABLE_SEATS.findIndex((_,i)=>!seatOccupied[i]);\n  if(si>=0){seatOccupied[si]=true;c.seatIdx=si;c.state='served';}\n  else{c.state='leaving';c.flip=true;}\n  queue=queue.filter(x=>x!==c);activeCust=null;\n  document.getElementById('day-earned').textContent=`${S.dayEarned} ₽`;\n  updateHdr();renderDaySC();ding();\n  addLog(`+${earned}₽ — ${r.name}${tip>0?` (+${tip}₽ чаевые)`:''}`, 'g');\n  updateQD();\n  if(queue.length){activeCust=queue[0];updateCustUI();}\n  else document.getElementById('cust-info').textContent='Ждём гостей...';\n  save();\n}\n\nfunction rejectCust(){\n  if(!activeCust)return;\n  const c=activeCust;c.state='leaving';c.flip=true;\n  S.rep=Math.max(0,S.rep-1);\n  queue=queue.filter(x=>x!==c);activeCust=null;\n  addLog(`${c.type.name} ушёл без покупки`,'n');updateHdr();updateQD();\n  if(queue.length){activeCust=queue[0];updateCustUI();}\n  else document.getElementById('cust-info').textContent='Ждём гостей...';\n}\n\nfunction toggleAuto(){\n  S.autoSell=!S.autoSell;\n  const b=document.getElementById('btn-auto');\n  b.textContent=`Авто: ${S.autoSell?'ВКЛ':'ВЫКЛ'}`;\n  b.style.background=S.autoSell?'var(--caramel)':'';\n  b.style.color=S.autoSell?'#fff':'';\n}\n\nfunction updateQD(){\n  for(let i=0;i<5;i++){\n    const d=document.getElementById(`qd${i}`),c=queue[i];\n    d.className='qd'+(c?(c.waitTime>c.patience*.7?' angry':' on'):'');\n  }\n}\n\nfunction addLog(msg,cls){\n  const l=document.getElementById('day-log'),e=document.createElement('div');\n  e.className=`le ${cls}`;e.textContent=msg;l.appendChild(e);l.scrollTop=l.scrollHeight;\n}\n\nfunction renderDaySC(){\n  const w=document.getElementById('day-sc');w.innerHTML='';\n  Object.keys(S.showcase).forEach(id=>{\n    const r=RECIPES.find(x=>x.id===id);if(!r)return;\n    const q=S.showcase[id]||0;\n    const d=document.createElement('div');d.className='sd-item'+(q===0?' out':'');\n    d.innerHTML=`${recipeIcon(id,24)}<span class=\"dn\">${r.name}</span><span class=\"dq\">${q}</span>`;\n    w.appendChild(d);\n  });\n}\n\n// ─── CANVAS DRAW ─────────────────────────────────────────\nfunction draw(){\n  const W=cv.width,H=cv.height;\n  ctx.clearRect(0,0,W,H);\n\n  // Sky / upper wall\n  const wallGrad=ctx.createLinearGradient(0,0,0,H*.55);\n  wallGrad.addColorStop(0,'#fdf0d8');wallGrad.addColorStop(1,'#f0dfc0');\n  ctx.fillStyle=wallGrad;ctx.fillRect(0,0,W,H*.55);\n\n  // Floor\n  const floorGrad=ctx.createLinearGradient(0,H*.55,0,H);\n  floorGrad.addColorStop(0,'#d8c4a0');floorGrad.addColorStop(1,'#c8b48a');\n  ctx.fillStyle=floorGrad;ctx.fillRect(0,H*.55,W,H*.45);\n\n  // Floor tiles\n  ctx.strokeStyle='rgba(180,150,100,.35)';ctx.lineWidth=1;\n  for(let x=0;x<W;x+=70){ctx.beginPath();ctx.moveTo(x,H*.55);ctx.lineTo(x,H);ctx.stroke();}\n  for(let y=H*.55;y<H;y+=50){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}\n\n  // Baseboard\n  ctx.fillStyle='#a07040';ctx.fillRect(0,H*.55,W,8);\n\n  // Windows\n  drawWindows(ctx,W,H);\n\n  // Wall deco\n  if(S.decor['painting'])drawPainting(ctx,80,50);\n  if(S.decor['plant'])drawPlant(ctx,W-70,H*.5);\n  if(S.decor['menu_board'])drawMenuBoard(ctx,240,45);\n  if(S.decor['lighting']){\n    const lg=ctx.createRadialGradient(W/2,0,5,W/2,0,W*.75);\n    lg.addColorStop(0,'rgba(255,220,100,.22)');lg.addColorStop(1,'rgba(255,220,100,0)');\n    ctx.fillStyle=lg;ctx.fillRect(0,0,W,H);\n  }\n  if(S.decor['jazz']){\n    ctx.font='20px serif';ctx.fillStyle='rgba(142,68,173,.6)';\n    ctx.fillText('♪',W-40,70);ctx.fillText('♫',W-65,55);ctx.fillText('♩',W-30,90);\n  }\n\n  // Tables\n  drawTables(ctx,H);\n\n  // Counter\n  drawCounter(ctx,W,H);\n\n  // Customers\n  custs.forEach(c=>{\n    if(c.state==='gone')return;\n    const bob=(c.state==='walking')?Math.sin(bobT+c.id*3)*2.5:0;\n    drawCust(ctx,c,c.x,c.y+bob,c.flip);\n    if(c.state==='waiting'){\n      const r=RECIPES.find(x=>x.id===c.want);\n      drawBubble(ctx,c.x,c.y-10,r?r.name:'...');\n      // patience bar\n      const pct=Math.max(0,1-c.waitTime/c.patience);\n      ctx.fillStyle=pct>.5?'#4a7c59':pct>.25?'#e67e22':'#c0392b';\n      ctx.fillRect(c.x-22,c.y-55,44*pct,5);\n      ctx.strokeStyle='rgba(0,0,0,.2)';ctx.lineWidth=1;ctx.strokeRect(c.x-22,c.y-55,44,5);\n    }\n    if(c.state==='eating'){\n      // cup/plate on table\n      const seat=TABLE_SEATS[c.seatIdx];\n      if(seat)drawEatingItem(ctx,seat.x,seat.y-20,c.want);\n    }\n  });\n}\n\nfunction drawWindows(ctx,W,H){\n  [[160,30],[400,30],[580,30]].forEach(([x,y])=>{\n    // Frame\n    ctx.fillStyle='#8b5e3c';ctx.fillRect(x,y,80,80);\n    // Glass\n    const sg=ctx.createLinearGradient(x+4,y+4,x+76,y+76);\n    sg.addColorStop(0,'rgba(135,200,235,.7)');sg.addColorStop(1,'rgba(200,235,255,.5)');\n    ctx.fillStyle=sg;ctx.fillRect(x+4,y+4,72,72);\n    // Cross\n    ctx.strokeStyle='rgba(255,255,255,.5)';ctx.lineWidth=2;\n    ctx.beginPath();ctx.moveTo(x+40,y+4);ctx.lineTo(x+40,y+76);ctx.stroke();\n    ctx.beginPath();ctx.moveTo(x+4,y+40);ctx.lineTo(x+76,y+40);ctx.stroke();\n    // Sill\n    ctx.fillStyle='#a07040';ctx.fillRect(x-4,y+80,88,8);\n    // Curtains\n    ctx.fillStyle='rgba(200,135,58,.3)';\n    ctx.fillRect(x+4,y+4,18,72);ctx.fillRect(x+58,y+4,14,72);\n  });\n}\n\nfunction drawPainting(ctx,x,y){\n  ctx.fillStyle='#8b5e3c';ctx.fillRect(x,y,100,75);\n  const pg=ctx.createLinearGradient(x+5,y+5,x+95,y+70);\n  pg.addColorStop(0,'#87ceeb');pg.addColorStop(1,'#6aade4');\n  ctx.fillStyle=pg;ctx.fillRect(x+5,y+5,90,65);\n  ctx.fillStyle='#4a7c59';ctx.beginPath();ctx.arc(x+30,y+45,16,0,Math.PI*2);ctx.fill();\n  ctx.fillStyle='#c8873a';ctx.beginPath();ctx.arc(x+60,y+35,12,0,Math.PI*2);ctx.fill();\n  ctx.strokeStyle='#8b5e3c';ctx.lineWidth=4;ctx.strokeRect(x,y,100,75);\n}\n\nfunction drawMenuBoard(ctx,x,y){\n  ctx.fillStyle='#2c3e50';ctx.fillRect(x,y,130,90);\n  ctx.strokeStyle='#c8873a';ctx.lineWidth=3;ctx.strokeRect(x,y,130,90);\n  ctx.fillStyle='#f5e6c8';ctx.font='bold 13px Nunito,sans-serif';ctx.textAlign='center';\n  ctx.fillText('МЕНЮ ДНЯ',x+65,y+22);\n  ctx.font='11px Nunito,sans-serif';ctx.fillStyle='rgba(245,230,200,.75)';\n  ['Круассан 80₽','Латте 150₽','Эклер 120₽','Лимонад 80₽'].forEach((t,i)=>ctx.fillText(t,x+65,y+38+i*14));\n}\n\nfunction drawPlant(ctx,x,y){\n  [[0,-20,18],[- 12,-8,14],[12,-12,12]].forEach(([dx,dy,r])=>{\n    ctx.fillStyle='#4a7c59';ctx.beginPath();ctx.arc(x+dx,y+dy,r,Math.PI,0);ctx.fill();\n    ctx.fillStyle='#3d6b4a';ctx.beginPath();ctx.arc(x+dx,y+dy+2,r*.7,Math.PI,0);ctx.fill();\n  });\n  ctx.fillStyle='#8b5e3c';ctx.fillRect(x-10,y,20,28);\n  ctx.fillStyle='#a07040';ctx.fillRect(x-12,y-2,24,6);\n}\n\nfunction drawTables(ctx,H){\n  const ty=H*.58;\n  [[100,ty],[230,ty],[350,ty]].forEach(([tx,ty2])=>{\n    // Table top\n    const tg=ctx.createLinearGradient(tx-38,ty2-5,tx+38,ty2+5);\n    tg.addColorStop(0,'#c8a060');tg.addColorStop(1,'#a07040');\n    ctx.fillStyle=tg;\n    ctx.beginPath();ctx.ellipse(tx,ty2,42,14,0,0,Math.PI*2);ctx.fill();\n    ctx.strokeStyle='#8b5e3c';ctx.lineWidth=2;\n    ctx.beginPath();ctx.ellipse(tx,ty2,42,14,0,0,Math.PI*2);ctx.stroke();\n    // Legs\n    ctx.fillStyle='#8b5e3c';\n    ctx.fillRect(tx-6,ty2+8,10,H-ty2-8);\n    ctx.fillRect(tx-4,H-30,8,30);\n    // Chairs\n    [-52,52].forEach(dx=>{\n      ctx.fillStyle='#a07040';\n      ctx.beginPath();ctx.ellipse(tx+dx,ty2+5,18,8,0,0,Math.PI*2);ctx.fill();\n      ctx.fillStyle='#8b5e3c';ctx.fillRect(tx+dx-4,ty2+12,6,20);ctx.fillRect(tx+dx-2,ty2+12,6,20);\n    });\n  });\n}\n\nfunction drawCounter(ctx,W,H){\n  const cy=H*.58;\n  // Counter back\n  ctx.fillStyle='#6b3a1a';ctx.fillRect(W-190,cy-40,190,H-cy+40);\n  // Counter top\n  const cg=ctx.createLinearGradient(W-190,cy-40,W,cy-40);\n  cg.addColorStop(0,'#a07040');cg.addColorStop(1,'#8b5e3c');\n  ctx.fillStyle=cg;ctx.fillRect(W-195,cy-48,200,18);\n  ctx.strokeStyle='#c8a060';ctx.lineWidth=2;ctx.strokeRect(W-195,cy-48,200,18);\n  // Showcase glass\n  ctx.fillStyle='rgba(180,220,240,.25)';ctx.fillRect(W-185,cy-45,130,38);\n  ctx.strokeStyle='#c8a060';ctx.lineWidth=1.5;ctx.strokeRect(W-185,cy-45,130,38);\n  // Items in showcase\n  const sItems=Object.keys(S.showcase).filter(k=>S.showcase[k]>0);\n  sItems.slice(0,4).forEach((id,i)=>{drawSmallItem(ctx,W-178+i*32,cy-36,id);});\n  // Coffee machine\n  drawCoffeeMachine(ctx,W-55,cy-80);\n  // Cashier area\n  ctx.fillStyle='#5c3317';ctx.fillRect(W-200,cy-48,14,H-cy+48);\n}\n\nfunction drawCoffeeMachine(ctx,x,y){\n  ctx.fillStyle='#333';ctx.fillRect(x-18,y,36,44);\n  ctx.fillStyle='#555';ctx.fillRect(x-15,y+3,30,16);\n  ctx.fillStyle='#c8873a';ctx.beginPath();ctx.arc(x,y+12,5,0,Math.PI*2);ctx.fill();\n  ctx.fillStyle='#c8873a';ctx.fillRect(x-3,y+20,6,10);\n  // steam\n  ctx.strokeStyle='rgba(180,180,180,.6)';ctx.lineWidth=1.5;\n  [x-5,x+5].forEach(sx=>{\n    ctx.beginPath();ctx.moveTo(sx,y-2);\n    ctx.quadraticCurveTo(sx-3,y-8,sx,y-14);ctx.stroke();\n  });\n}\n\nfunction drawSmallItem(ctx,x,y,id){\n  const clrs={croissant:'#f4c777',cinnamon_bun:'#c8873a',muffin:'#7b6fa0',baguette:'#e8c87a',\n    eclair:'#5c3317',espresso:'#3d1c00',cappuccino:'#c4956a',latte:'#d4a87a',lemonade:'#fffaaa'};\n  ctx.fillStyle=clrs[id]||'#aaa';\n  ctx.beginPath();ctx.arc(x+8,y+8,8,0,Math.PI*2);ctx.fill();\n}\n\nfunction drawEatingItem(ctx,x,y,id){\n  const drink=['espresso','cappuccino','latte','lemonade','matcha_latte'].includes(id);\n  if(drink){\n    ctx.fillStyle='#e8c4a0';ctx.beginPath();ctx.ellipse(x,y,12,5,0,0,Math.PI*2);ctx.fill();\n    ctx.fillStyle=id==='lemonade'?'#fffaaa':id==='matcha_latte'?'#4a7c59':'#8b5e3c';\n    ctx.fillRect(x-6,y-14,12,14);\n  }else{\n    ctx.fillStyle='#e8c4a0';ctx.beginPath();ctx.ellipse(x,y,14,5,0,0,Math.PI*2);ctx.fill();\n    ctx.fillStyle='#f4c777';ctx.beginPath();ctx.arc(x,y-6,7,0,Math.PI*2);ctx.fill();\n  }\n}\n\nfunction drawBubble(ctx,x,y,text){\n  ctx.save();ctx.translate(x,y-55);\n  const w=Math.max(80,text.length*6+20),h=34;\n  ctx.fillStyle='#fff';ctx.strokeStyle='#c8873a';ctx.lineWidth=2;\n  ctx.beginPath();\n  if(ctx.roundRect)ctx.roundRect(-w/2,-h,w,h,8);\n  else ctx.rect(-w/2,-h,w,h);\n  ctx.fill();ctx.stroke();\n  ctx.fillStyle='#fff';ctx.beginPath();ctx.moveTo(-7,0);ctx.lineTo(7,0);ctx.lineTo(0,10);ctx.closePath();ctx.fill();\n  ctx.strokeStyle='#c8873a';ctx.lineWidth=1;ctx.moveTo(-7,0);ctx.lineTo(0,10);ctx.lineTo(7,0);ctx.stroke();\n  ctx.fillStyle='#1C0A00';ctx.font='bold 11px Nunito,sans-serif';ctx.textAlign='center';\n  ctx.fillText(text,-0,-h/2+4);\n  ctx.restore();\n}\n\n// ─── DRAW CUSTOMER ───────────────────────────────────────\nfunction drawCust(ctx,c,x,y,flip){\n  ctx.save();\n  ctx.translate(x,y);\n  if(flip)ctx.scale(-1,1);\n\n  const t=c.type;\n  const sitting=c.state==='eating';\n\n  // Shoes\n  ctx.fillStyle='#2c1a0a';\n  if(sitting){\n    ctx.fillRect(-12,10,10,6);ctx.fillRect(2,10,10,6);\n  }else{\n    ctx.fillRect(-12,20,10,8);ctx.fillRect(2,20,10,8);\n  }\n\n  // Legs\n  ctx.fillStyle=t.id==='bizlady'?'#1a0a00':t.id==='granny'?'#555':'#2c3040';\n  if(sitting){\n    ctx.fillRect(-12,-5,10,18);ctx.fillRect(2,-5,10,18);\n  }else{\n    const legSwing=Math.sin(bobT+c.id*3)*8;\n    ctx.save();ctx.rotate((legSwing)*Math.PI/180);ctx.fillRect(-8,-2,8,24);ctx.restore();\n    ctx.save();ctx.rotate((-legSwing)*Math.PI/180);ctx.fillRect(0,-2,8,24);ctx.restore();\n  }\n\n  // Skirt/dress for granny & bizlady\n  if(t.id==='granny'){ctx.fillStyle='#9b59b6';ctx.beginPath();ctx.moveTo(-14,-5);ctx.lineTo(14,-5);ctx.lineTo(10,14);ctx.lineTo(-10,14);ctx.closePath();ctx.fill();}\n  if(t.id==='bizlady'){ctx.fillStyle='#1a2a3a';ctx.fillRect(-10,-22,20,18);}\n\n  // Body\n  ctx.fillStyle=t.shirt;\n  if(!['granny','bizlady'].includes(t.id))ctx.fillRect(-11,-22,22,20);\n\n  // Arms\n  ctx.fillStyle=t.shirt;\n  if(sitting){\n    ctx.fillRect(-18,-15,8,12);ctx.fillRect(10,-15,8,12);\n  }else{\n    const arm=Math.sin(bobT+c.id*3+Math.PI)*6;\n    ctx.save();ctx.rotate((arm+12)*Math.PI/180);ctx.fillRect(-16,-18,6,16);ctx.restore();\n    ctx.save();ctx.rotate((-arm-12)*Math.PI/180);ctx.fillRect(10,-18,6,16);ctx.restore();\n  }\n\n  // Neck\n  ctx.fillStyle='#f0c090';ctx.fillRect(-4,-26,8,6);\n\n  // Head\n  ctx.fillStyle='#f0c090';ctx.beginPath();ctx.arc(0,-34,11,0,Math.PI*2);ctx.fill();\n\n  // Hair\n  ctx.fillStyle=t.hair;\n  if(t.id==='hipster'){\n    ctx.beginPath();ctx.arc(0,-46,6,0,Math.PI*2);ctx.fill();\n    ctx.fillRect(-11,-38,22,10);\n    // beard\n    ctx.fillStyle='#2c1a0a';ctx.beginPath();ctx.arc(0,-26,5,0,Math.PI);ctx.fill();\n    // glasses\n    ctx.strokeStyle='#333';ctx.lineWidth=1.5;\n    ctx.strokeRect(-11,-37,9,7);ctx.strokeRect(2,-37,9,7);\n    ctx.beginPath();ctx.moveTo(-2,-33);ctx.lineTo(2,-33);ctx.stroke();\n  }else if(t.id==='student'){\n    ctx.beginPath();ctx.arc(0,-43,8,Math.PI,0);ctx.fill();\n    // backpack\n    ctx.fillStyle='#e74c3c';ctx.fillRect(11,-22,9,18);ctx.fillRect(12,-20,7,4);\n  }else if(t.id==='bizlady'){\n    ctx.beginPath();ctx.arc(0,-43,9,Math.PI*.1,Math.PI*.9);ctx.fill();\n    ctx.fillRect(-9,-44,18,8);\n    // briefcase\n    ctx.fillStyle='#2c3e50';ctx.fillRect(12,-12,12,9);\n    ctx.strokeStyle='#fff';ctx.lineWidth=1;ctx.strokeRect(14,-14,8,4);\n  }else if(t.id==='tourist'){\n    ctx.beginPath();ctx.arc(0,-43,9,Math.PI*.1,Math.PI*.9);ctx.fill();\n    // hat\n    ctx.fillStyle='#e67e22';ctx.fillRect(-13,-52,26,7);ctx.fillRect(-9,-60,18,10);\n    // camera\n    ctx.fillStyle='#333';ctx.fillRect(-18,-16,11,8);ctx.fillStyle='#666';ctx.beginPath();ctx.arc(-13,-12,3,0,Math.PI*2);ctx.fill();\n  }else if(t.id==='granny'){\n    ctx.fillStyle='#ddd';ctx.beginPath();ctx.arc(0,-43,9,Math.PI,0);ctx.fill();\n    ctx.fillRect(-9,-44,18,8);\n    // shawl\n    ctx.fillStyle='rgba(155,89,182,.4)';ctx.beginPath();ctx.moveTo(-16,-22);ctx.lineTo(16,-22);ctx.lineTo(10,0);ctx.lineTo(-10,0);ctx.closePath();ctx.fill();\n  }else if(t.id==='mom'){\n    ctx.beginPath();ctx.arc(0,-43,9,Math.PI*.1,Math.PI*.9);ctx.fill();\n    ctx.fillRect(-9,-44,18,8);\n    // stroller\n    if(!sitting){\n      ctx.fillStyle='#e91e8c';ctx.fillRect(13,-18,20,14);\n      ctx.strokeStyle='#e91e8c';ctx.lineWidth=2;ctx.beginPath();ctx.moveTo(13,-18);ctx.lineTo(11,-8);ctx.stroke();\n      ctx.fillStyle='#333';[14,30].forEach(dx=>{ctx.beginPath();ctx.arc(dx,-3,4,0,Math.PI*2);ctx.fill();});\n    }\n  }else{\n    ctx.beginPath();ctx.arc(0,-43,9,Math.PI*.1,Math.PI*.9);ctx.fill();ctx.fillRect(-9,-44,18,8);\n  }\n\n  // Eyes\n  ctx.fillStyle='#1C0A00';\n  ctx.beginPath();ctx.arc(-4,-34,1.5,0,Math.PI*2);ctx.fill();\n  ctx.beginPath();ctx.arc(4,-34,1.5,0,Math.PI*2);ctx.fill();\n\n  // Smile\n  ctx.strokeStyle='#1C0A00';ctx.lineWidth=1.2;\n  ctx.beginPath();ctx.arc(0,-30,3.5,0.2,Math.PI-.2);ctx.stroke();\n\n  ctx.restore();\n}\n\n// ─── END DAY ─────────────────────────────────────────────\nfunction endDay(){\n  if(!dayRunning)return;\n  dayRunning=false;if(animId)cancelAnimationFrame(animId);\n  custs=[];queue=[];Object.keys(seatOccupied).forEach(k=>delete seatOccupied[k]);\n  if(S.dayEarned>S.totalStats.maxDay)S.totalStats.maxDay=S.dayEarned;\n  if(S.rep>=80)S.totalStats.repDays++;\n  if(S.day>=5)S.totalStats.day5=true;\n  const sold=Object.values(S.dayStats.sold).reduce((a,b)=>a+b,0);\n  if(sold>10)S.rep=Math.min(100,S.rep+3);\n  if(S.dayStats.unhappy>3)S.rep=Math.max(0,S.rep-3);\n  save();switchPhase('evening');\n}\n\n// ─── EVENING ─────────────────────────────────────────────\nfunction renderEvening(){\n  document.getElementById('ev-earned').textContent=`${S.dayStats.earned} ₽`;\n  const ts=Object.values(S.dayStats.sold).reduce((a,b)=>a+b,0);\n  document.getElementById('ev-sold').textContent=ts;\n  document.getElementById('ev-rep').textContent=`${Math.round(S.rep)}%`;\n  const sb=document.getElementById('sales-bars');sb.innerHTML='';\n  const sorted=Object.entries(S.dayStats.sold).sort((a,b)=>b[1]-a[1]);\n  const mx=sorted[0]?sorted[0][1]:1;\n  sorted.forEach(([id,cnt])=>{\n    const r=RECIPES.find(x=>x.id===id);if(!r)return;\n    const row=document.createElement('div');row.className='sbr';\n    row.innerHTML=`<span class=\"nm\">${r.name}</span><div class=\"bar-bg\"><div class=\"bar-f\" style=\"width:0%\" data-p=\"${cnt/mx*100}\"></div></div><span class=\"cnt\">${cnt}</span>`;\n    sb.appendChild(row);\n  });\n  setTimeout(()=>document.querySelectorAll('.bar-f').forEach(el=>el.style.width=el.dataset.p+'%'),80);\n  const ll=document.getElementById('lft-list');ll.innerHTML='';\n  let hasL=false;\n  Object.keys(S.showcase).forEach(id=>{\n    const q=S.showcase[id]||0;if(!q)return;hasL=true;\n    const r=RECIPES.find(x=>x.id===id);\n    const d=document.createElement('div');d.className='lft-item';\n    d.innerHTML=`${recipeIcon(id,28)}<span class=\"ln\">${r?r.name:id}</span><span class=\"lq\">${q} шт × ${Math.round((r?r.price:50)*.5)}₽</span>`;\n    ll.appendChild(d);\n  });\n  if(!hasL)ll.innerHTML='<div style=\"color:rgba(28,10,0,.4);font-size:13px\">Всё продано! 🎉</div>';\n  checkUnlocks();\n}\n\nfunction checkUnlocks(){\n  const u=document.getElementById('unlock-sec');u.style.display='none';\n  let unlock=null;\n  if(S.totalStats.croissants>=20&&!S.unlocked.includes('almond_croissant'))unlock={id:'almond_croissant',desc:'Продал 20 круассанов!'};\n  else if(S.totalStats.maxDay>=5000&&!S.unlocked.includes('honey_cake'))unlock={id:'honey_cake',desc:'Выручка 5000₽ за день!'};\n  else if(S.totalStats.exps>=1&&!S.unlocked.includes('recipe_of_day'))unlock={id:'recipe_of_day',desc:'Удачный эксперимент!'};\n  else if(S.totalStats.day5&&!S.unlocked.includes('matcha_latte'))unlock={id:'matcha_latte',desc:'5 дней позади!'};\n  else if(S.totalStats.repDays>=3&&!S.unlocked.includes('breakfast'))unlock={id:'breakfast',desc:'Репутация 80%+ три дня!'};\n  if(unlock){\n    S.unlocked.push(unlock.id);\n    const r=RECIPES.find(x=>x.id===unlock.id);\n    document.getElementById('unlock-name').textContent=r?r.name:unlock.id;\n    document.getElementById('unlock-desc').textContent=unlock.desc;\n    u.style.display='block';fanfare();save();\n  }\n}\n\nfunction sellLeftovers(){\n  let e=0;\n  Object.keys(S.showcase).forEach(id=>{const r=RECIPES.find(x=>x.id===id),q=S.showcase[id]||0;if(q&&r)e+=Math.round(r.price*.5)*q;});\n  S.money+=e;S.showcase={};notify(`Продано остатков на ${e}₽`,'g');updateHdr();renderEvening();\n}\nfunction throwLeftovers(){S.showcase={};notify('Остатки выброшены','i');renderEvening();}\n\nfunction nextDay(){\n  S.day++;S.weather=WEATHERS[Math.floor(Math.random()*WEATHERS.length)];\n  S.showcase={};budgetUsed=0;S.dayStats={earned:0,sold:{},unhappy:0,exp:0};S.dayEarned=0;\n  S.money+=50;updateHdr();save();switchPhase('morning');\n}\n\n// ─── DECOR ────────────────────────────────────────────────\nfunction renderDecor(){\n  drawDecorPreview();\n  const l=document.getElementById('decor-list');l.innerHTML='';\n  DECORS.forEach(item=>{\n    const owned=!!S.decor[item.id];\n    const d=document.createElement('div');d.className='di-item';\n    d.innerHTML=`<div class=\"dico\">${item.icon}</div>\n    <div class=\"dinfo\"><div class=\"dtitle\">${item.name}</div><div class=\"ddesc\">${item.desc}</div></div>\n    ${owned?'<span class=\"owned-badge\">Куплено</span>':`<div><div class=\"dprice\">${item.price}₽</div><button class=\"btn btn-p\" style=\"font-size:11px;padding:5px 10px;margin-top:3px\" onclick=\"buyDecor('${item.id}')\">Купить</button></div>`}`;\n    l.appendChild(d);\n  });\n}\n\nfunction drawDecorPreview(){\n  const dc=document.getElementById('dc'),dctx=dc.getContext('2d'),W=dc.width,H=dc.height;\n  dctx.clearRect(0,0,W,H);\n  // Wall\n  const wg=dctx.createLinearGradient(0,0,0,H*.6);\n  wg.addColorStop(0,'#fdf0d8');wg.addColorStop(1,'#f0dfc0');\n  dctx.fillStyle=wg;dctx.fillRect(0,0,W,H*.6);\n  // Floor\n  const fg=dctx.createLinearGradient(0,H*.6,0,H);\n  fg.addColorStop(0,'#d8c4a0');fg.addColorStop(1,'#c8b48a');\n  dctx.fillStyle=fg;dctx.fillRect(0,H*.6,W,H*.4);\n  dctx.strokeStyle='rgba(180,150,100,.3)';dctx.lineWidth=1;\n  for(let x=0;x<W;x+=60){dctx.beginPath();dctx.moveTo(x,H*.6);dctx.lineTo(x,H);dctx.stroke();}\n  for(let y=H*.6;y<H;y+=40){dctx.beginPath();dctx.moveTo(0,y);dctx.lineTo(W,y);dctx.stroke();}\n  dctx.fillStyle='#a07040';dctx.fillRect(0,H*.6,W,7);\n  // Windows\n  [[60,25],[280,25]].forEach(([x,y])=>{\n    dctx.fillStyle='#8b5e3c';dctx.fillRect(x,y,80,75);\n    dctx.fillStyle='rgba(135,200,235,.65)';dctx.fillRect(x+4,y+4,72,67);\n    dctx.strokeStyle='rgba(255,255,255,.4)';dctx.lineWidth=1.5;\n    dctx.beginPath();dctx.moveTo(x+40,y+4);dctx.lineTo(x+40,y+71);dctx.stroke();\n    dctx.beginPath();dctx.moveTo(x+4,y+38);dctx.lineTo(x+76,y+38);dctx.stroke();\n    dctx.fillStyle='#a07040';dctx.fillRect(x-4,y+75,88,7);\n  });\n  // Decor\n  if(S.decor['painting'])drawPainting(dctx,160,25);\n  if(S.decor['plant'])drawPlant(dctx,W-60,H*.55);\n  if(S.decor['menu_board']){dctx.fillStyle='#2c3e50';dctx.fillRect(420,25,110,80);dctx.strokeStyle='#c8873a';dctx.lineWidth=2;dctx.strokeRect(420,25,110,80);}\n  if(S.decor['lighting']){\n    const lg=dctx.createRadialGradient(W/2,0,5,W/2,0,W*.7);\n    lg.addColorStop(0,'rgba(255,220,100,.2)');lg.addColorStop(1,'rgba(255,220,100,0)');\n    dctx.fillStyle=lg;dctx.fillRect(0,0,W,H);\n  }\n  if(S.decor['jazz']){dctx.font='20px serif';dctx.fillStyle='rgba(142,68,173,.5)';dctx.fillText('♪',W-35,60);dctx.fillText('♫',W-60,45);}\n  if(S.decor['table']){\n    [[100,H*.62],[230,H*.62],[360,H*.62]].forEach(([tx,ty])=>{\n      dctx.fillStyle='#a07040';dctx.beginPath();dctx.ellipse(tx,ty,40,13,0,0,Math.PI*2);dctx.fill();\n      dctx.strokeStyle='#8b5e3c';dctx.lineWidth=1.5;dctx.beginPath();dctx.ellipse(tx,ty,40,13,0,0,Math.PI*2);dctx.stroke();\n      dctx.fillStyle='#8b5e3c';dctx.fillRect(tx-5,ty+10,8,H-ty-10);\n    });\n  }\n  // Counter\n  dctx.fillStyle='#6b3a1a';dctx.fillRect(W-160,H*.58,160,H*.42);\n  dctx.fillStyle='#a07040';dctx.fillRect(W-165,H*.55,168,15);\n}\n\nfunction buyDecor(id){\n  const item=DECORS.find(x=>x.id===id);if(!item)return;\n  if(S.decor[id]){notify('Уже куплено','i');return;}\n  if(S.money<item.price){notify(`Нужно ${item.price}₽`,'b');return;}\n  S.money-=item.price;S.decor[id]=true;\n  notify(`${item.name} добавлен!`,'g');fanfare();updateHdr();save();renderDecor();\n}\n\n// ─── INIT ─────────────────────────────────────────────────\nasync function init(){\n  await load();\n  updateHdr();\n  switchPhase('morning');\n}\ninit();\n</script>\n</body>\n</html>\n";

function json(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', ...CORS },
  });
}

function userKey(request) {
  const ip = request.headers.get('CF-Connecting-IP') || 'anonymous';
  return `save:${ip}`;
}

async function handleSave(request, env) {
  const contentLength = parseInt(request.headers.get('Content-Length') || '0', 10);
  if (contentLength > MAX_PAYLOAD) return json({ error: 'Payload too large' }, 413);

  let body;
  try {
    body = await request.text();
    JSON.parse(body);
  } catch {
    return json({ error: 'Invalid JSON' }, 400);
  }

  const key = userKey(request);
  await env.LAFOURNEE_KV.put(key, body, { expirationTtl: 60 * 60 * 24 * 365 });
  return json({ ok: true });
}

async function handleLoad(request, env) {
  const key = userKey(request);
  const value = await env.LAFOURNEE_KV.get(key, 'text');
  if (!value) return json({ ok: false, error: 'No save found' }, 404);

  try {
    return json(JSON.parse(value));
  } catch {
    return json({ error: 'Corrupted save' }, 500);
  }
}

export default {
  async fetch(request, env) {
    const { method, pathname } = Object.assign(
      { method: request.method },
      { pathname: new URL(request.url).pathname }
    );

    if (method === 'OPTIONS') return new Response(null, { status: 204, headers: CORS });

    if (pathname === '/api/save' && method === 'POST') return handleSave(request, env);
    if (pathname === '/api/load' && method === 'GET')  return handleLoad(request, env);

    // Serve game for any other GET (/ or unknown paths)
    if (method === 'GET') {
      return new Response(GAME_HTML, {
        headers: {
          'Content-Type': 'text/html; charset=utf-8',
          'Cache-Control': 'public, max-age=60',
        },
      });
    }

    return new Response('Not Found', { status: 404 });
  },
};
